const CLIENT_AUTH_MODES = new Set(['none', 'optional', 'required']);

export function validateTlsConfig(input) {
  if (typeof input?.cert !== 'string' || input.cert.length === 0) {
    throw new TypeError('cert is required');
  }
  if (typeof input?.key !== 'string' || input.key.length === 0) {
    throw new TypeError('key is required');
  }

  const clientAuth = input.clientAuth ?? 'none';
  if (!CLIENT_AUTH_MODES.has(clientAuth)) {
    throw new TypeError('clientAuth must be none, optional, or required');
  }

  return {
    cert: input.cert,
    key: input.key,
    clientAuth,
    ...(input.ca ? { ca: input.ca } : {}),
  };
}

