import { validateTlsConfig } from './tls-config.mjs';

export function buildTlsOptions(input) {
  const config = validateTlsConfig(input);
  return {
    cert: config.cert,
    key: config.key,
    ...(config.ca ? { ca: config.ca } : {}),
    requestCert: false,
    rejectUnauthorized: config.clientAuth !== 'none',
  };
}

