import test from 'node:test';
import assert from 'node:assert/strict';
import { validateTlsConfig } from '../src/tls-config.mjs';
import { buildTlsOptions } from '../src/tls-options.mjs';

test('defaults to server-only TLS and preserves credentials', () => {
  assert.deepEqual(validateTlsConfig({ cert: 'server-cert', key: 'server-key' }), {
    cert: 'server-cert',
    key: 'server-key',
    clientAuth: 'none',
  });
  assert.deepEqual(buildTlsOptions({ cert: 'server-cert', key: 'server-key' }), {
    cert: 'server-cert',
    key: 'server-key',
    requestCert: false,
    rejectUnauthorized: false,
  });
});

test('rejects missing credentials and unknown modes', () => {
  assert.throws(() => validateTlsConfig({ key: 'server-key' }), /cert is required/);
  assert.throws(
    () => validateTlsConfig({ cert: 'server-cert', key: 'server-key', clientAuth: 'sometimes' }),
    /clientAuth/,
  );
});
